code.C:
#include <stdio.h>
#include <math.h>
int main() {
    double dH, dL, dR, k;
    while (scanf("%lf %lf %lf %lf", &dH, &dL, &dR, &k) == 4 && (dH != 0 || dL != 0 || dR != 0 || k != 0)) {
        double x = (dR * dH) / (dH + dL);
        double t1 = sqrt(pow(x, 2) + pow(dH, 2));
        double t2 = sqrt(pow(dR - x, 2) + pow(dL, 2)) * k;
        double ans = t1 + t2;
        printf("%.2f\n", ans);
    }
    return 0;
}

