import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        while (sc.hasNextDouble()) {
            double dH = sc.nextDouble();
            double dL = sc.nextDouble();
            double dR = sc.nextDouble();
            double k = sc.nextDouble();
            if (dH == 0 && dL == 0 && dR == 0 && k == 0) break;
            double x = (dR * dH) / (dH + dL);
            double t1 = Math.sqrt(Math.pow(x, 2) + Math.pow(dH, 2));
            double t2 = Math.sqrt(Math.pow(dR - x, 2) + Math.pow(dL, 2)) * k;
            double ans = t1 + t2;
            System.out.printf("%.2f\n", ans);
        }
    }
}

